<?php
namespace Tests\Feature;use App\Domain\Hunts\Exceptions\InvalidHuntingZoneException;use App\Domain\Hunts\WeightedMonsterSelector;use App\Domain\Random\RandomNumberGenerator;use App\Models\Character;use App\Models\User;use App\Models\Zone;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Tests\TestCase;class HuntFixedRandom implements RandomNumberGenerator{private $v;public function __construct($v){$this->v=$v;}public function randomInt(int $min,int $max):int{return$this->v;}}class WeightedMonsterSelectorTest extends TestCase{use RefreshDatabase;public function test_weight_boundaries(){$this->seed(WorldCatalogSeeder::class);$c=Character::factory()->for(User::factory())->create(['level'=>1]);$z=Zone::where('code','grey_oak_forest')->first();DB::transaction(function()use($z,$c){$this->assertSame('grey_wolf',(new WeightedMonsterSelector(new HuntFixedRandom(1)))->select($z,$c)->code);$this->assertSame('grey_wolf',(new WeightedMonsterSelector(new HuntFixedRandom(50)))->select($z,$c)->code);$this->assertSame('young_boar',(new WeightedMonsterSelector(new HuntFixedRandom(51)))->select($z,$c)->code);});}public function test_invalid_zone_fails(){$this->seed(WorldCatalogSeeder::class);$c=Character::factory()->for(User::factory())->create();$z=Zone::where('code','dawn_village')->first();$this->expectException(InvalidHuntingZoneException::class);(new WeightedMonsterSelector(new HuntFixedRandom(1)))->select($z,$c);}}
